print("Expanding final batch ...")
sd = read("schemes_data.py")
count = 0
for slug, nd in E.items():
    sm = '"slug": "' + slug + '"'
    am = '"slug":"' + slug + '"'
    p = sd.find(sm)
    if p < 0: p = sd.find(am)
    if p < 0:
        print("  Skip: " + slug)
        continue
    hs = sd.find('"hi":', p)
    if hs < 0 or hs > p + 2000: hs = sd.find('"hi" :', p)
    if hs < 0 or hs > p + 2000:
        print("  Skip: " + slug + " hi?")
        continue
    hb = sd.find('{', hs)
    d = 0; he = hb
    for i in range(hb, len(sd)):
        if sd[i] == '{': d += 1
        elif sd[i] == '}':
            d -= 1
            if d == 0: he = i + 1; break
    try: ch = ast.literal_eval(sd[hb:he])
    except:
        print("  Skip: " + slug + " parse")
        continue
    for k in nd: ch[k] = nd[k]
    ns = "{\n"
    for k, v in ch.items(): ns += '   "' + k + '": ' + repr(v) + ',\n'
    ns += "  }"
    sd = sd[:hb] + ns + sd[he:]
    count += 1
    print("  Done: " + slug)
write("schemes_data.py", sd)
print("\nExpanded " + str(count) + " schemes")
print("\nRebuilding ...")
os.chdir(REPO)
r = os.system(sys.executable + " generate.py")
if r == 0: print("OK!")
else: print("ERROR"); sys.exit(1)
